                          _handleOpenTripChat(
                            context,
                            routeId: routeId,
                            driverUid: driverUid,
                            counterpartName: driverSnapshot?.name,
                            counterpartSubtitle: driverSnapshot?.plate,
                          ),
                        ),
              ),
            );
          }

          final routeDriverId =
              _nullableToken(routeData?['driverId'] as String?);
          final driverStream = routeDriverId == null
              ? null
              : _observePassengerTrackingStreamsUseCase
                  .watchDriverDocument(routeDriverId);
          return StreamBuilder<DocumentSnapshot<Map<String, dynamic>>>(
            stream: driverStream,
            builder: (context, driverDocSnapshot) {
              final driverData = driverDocSnapshot.data?.data();
              final isSoftLockMode = _resolvePassengerSoftLockMode(
                routeData: routeData,
                driverData: driverData,
              );
              return StreamBuilder<DocumentSnapshot<Map<String, dynamic>>>(
                stream: _observePassengerTrackingStreamsUseCase
                    .watchPassengerDocument(
                  routeId: routeId,
                  passengerUid: user.uid,
                ),
                builder: (context, passengerSnapshot) {
                  final passengerData = passengerSnapshot.data?.data();
                  final passengerEtaSourceLabel =
                      _resolveEtaSourceLabelFromPassengerData(
                    passengerData,
                  );
                  final fallbackEtaSourceLabel =
                      etaSourceFromQuery ?? passengerEtaSourceLabel;
                  return StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
                    stream: _observePassengerTrackingStreamsUseCase
                        .watchRouteAnnouncements(routeId, limit: 20),
                    builder: (context, announcementSnapshot) {
                      final latestAnnouncement = _resolveLatestAnnouncementData(
                        announcementSnapshot.data,
                      );
                      final notificationUiState =
                          _passengerNotificationUiService.resolve(
                        hasActiveTrip: hasActiveTrip,
                        routeData: routeData,
                        passengerData: passengerData,
                        announcementData: latestAnnouncement,
                        activeTripData: activeTripData,
                      );
                      final driverSnapshot = _toPassengerDriverSnapshotInfo(
                        notificationUiState.driverSnapshot,
                      );
                      final driverProfileSnapshot =
                          _toPassengerDriverSnapshotFromDriverData(
                        driverData,
                      );
                      final effectiveDriverSnapshot =
                          driverSnapshot ?? driverProfileSnapshot;

                      return StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
                        stream: _observePassengerTrackingStreamsUseCase
                            .watchRouteStops(routeId),
                        builder: (context, stopSnapshot) {
                          final stops = _resolvePassengerStops(
                            stopSnapshot.data,
                          );
                          final activeTripDriverUid = _nullableToken(
                            activeTripData?['driverId'] as String?,
                          );
                          return buildTrackingWithEtaSource(
                            fallbackEtaSourceLabel: fallbackEtaSourceLabel,
                            passengerData: passengerData,
                            isSoftLockMode: isSoftLockMode,
                            driverNote: notificationUiState.announcementNote,
                            morningReminderNote:
                                notificationUiState.morningReminderNote,
                            vacationModeNote:
                                notificationUiState.vacationModeNote,
                            driverSnapshot: effectiveDriverSnapshot,
                            driverUid: activeTripDriverUid ?? routeDriverId,
                            stops: stops,
                          );
                        },
                      );
                    },
                  );
                },
              );
            },
          );
        },
      );
    },
  );
}
